#!/usr/bin/env python3
"""
Chitragupta installer — auto-generated.
Run from your project root:

    cd /mnt/d/chitragupta && python install.py

Creates all folders, writes all files, installs new deps.
"""
import os, sys, base64
from pathlib import Path

ROOT = Path(__file__).parent
FILES = {
    "api/__init__.py": "",
    "api/app.py": "",
    "api/dependencies.py": "",
    "api/models.py": "",
    "api/routers/__init__.py": "",
    "api/routers/analysis.py": "",
    "api/routers/databases.py": "",
    "api/routers/entries.py": "",
    "api/routers/relations.py": "",
    "api/routers/session.py": "",
    "api/routers/voice.py": "",
    "api_server.py": "",
    "config/settings.py": "",
    "core/confirmation.py": "",
    "core/conversation_engine.py": "",
    "core/conversation_ui.py": "",
    "core/dialogue_fsm.py": "",
    "core/json_builder.py": "",
    "core/session_cache.py": "",
    "core/session_memory.py": "",
    "core/skip_tracker.py": "",
    "main.py": "",
    "nlp/intent_parser.py": "",
    "nlp/schema_inferencer.py": "",
    "notion/notion_client.py": "",
    "notion/schema_manager.py": "",
    "voice/whisper_handler.py": "",
}

print('\n📦  Chitragupta Installer\n')
for rel, b64 in FILES.items():
    dest = ROOT / rel
    dest.parent.mkdir(parents=True, exist_ok=True)
    dest.write_bytes(base64.b64decode(b64))
    print(f'  ✓  {rel}')

print('\n📥  Installing dependencies...')
ret = os.system(f'{sys.executable} -m pip install fastapi uvicorn python-multipart --quiet --break-system-packages')
if ret == 0:
    print('  ✓  fastapi, uvicorn, python-multipart installed')
else:
    print('  ⚠  pip install failed — run manually:')
    print('     pip install fastapi uvicorn python-multipart')

print('\n✅  Done.')
print('💡  CLI:  python main.py')
print('🌐  API:  python api_server.py')
print('📖  Docs: http://localhost:8000/docs')
print('🔑  Remember to set API_KEY in .env before starting the API server.')
